+     if (flags < 0) 
+     {
+ 	kdError(900) << k_lineinfo << "fcntl(F_GETFL): " << perror << "\n";
+ 	return ret;
+     }
++    oflags = flags;
+     if (block)
+ 	flags &= ~O_NONBLOCK;
+     else
+ 	flags |= O_NONBLOCK;
+-    if (fcntl(m_Fd, F_SETFL, flags) < 0) 
++    if (oflags != flags && fcntl(m_Fd, F_SETFL, flags) < 0) 
+     {
++      if (errno != EAGAIN) {
+ 	kdError(900) << k_lineinfo << "fcntl(F_SETFL): " << perror << "\n";
+-	return ret;
++      } // we get EAGAIN when the slave process is gone...
++      return ret;
+     }
+ 
+     int nbytes;

1. Back out patch-su.cpp. The addition of the -m arg is unnecessary.

